import 'package:flutter/material.dart';
import 'package:local_auth/local_auth.dart';
import 'package:shared_preferences/shared_preferences.dart';

class BiometricAuth {
  Future<void> authenticate() async {
    final localAuth = LocalAuthentication();
    
    SharedPreferences prefs = await SharedPreferences.getInstance();
    bool isAuthenticated = (await prefs.getString('authentication')) == 'true';

    if (!isAuthenticated) {
      AuthenticationResult result = await localAuth.authenticate(
        localizedReason: 'Authenticate to continue',
        options: const MethodCallOptions(overrideOnlyAvailableMethods: true),
      );
      
      switch (result.status) {
        case AuthenticationStatus.authorized:
          prefs.setString('authentication', 'true');
          break;
        
        // handle password fallback, if biometric isn't available
        case AuthenticationStatus.notAvailable:
          // Show a dialog to the user informing them that their device doesn’t support fingerprint scanning or face recognition
          print('Biometric not supported');
          break;
        
        case AuthenticationStatus.denied:
          // Show a dialog to the user informing them that they can enable it in settings
          print('User denied biometric authentication');
          break;
      }
    } else {
      // Skip login screen if already authenticated
      print('Already Authenticated. Proceed to next screen');
    }
  }
}